  3→import android.content.Context
  4→import android.os.Bundle
  5→import android.view.View
  6→import androidx.fragment.app.Fragment
  7→import androidx.lifecycle.Observer
  8→import androidx.lifecycle.ViewModelProvider
  9→import androidx.recyclerview.widget.LinearLayoutManager
 10→import androidx.recyclerview.widget.RecyclerView
 11→import org.wordpress.android.R
 12→import org.wordpress.android.WordPress
 13→import org.wordpress.android.databinding.HistoryListFragmentBinding
 14→import org.wordpress.android.fluxc.model.SiteModel
 15→import org.wordpress.android.ui.history.HistoryAdapter
 16→import org.wordpress.android.ui.history.HistoryListItem
 17→import org.wordpress.android.ui.history.HistoryListItem.Revision
 18→import org.wordpress.android.util.WPSwipeToRefreshHelper
 19→import org.wordpress.android.util.extensions.getSerializableCompat
 20→import org.wordpress.android.util.helpers.SwipeToRefreshHelper
 21→import org.wordpress.android.viewmodel.history.HistoryViewModel
 22→import org.wordpress.android.viewmodel.history.HistoryViewModel.HistoryListStatus
 23→import javax.inject.Inject
 24→
 25→class HistoryListFragment : Fragment(R.layout.history_list_fragment) {
 26→    private lateinit var swipeToRefreshHelper: SwipeToRefreshHelper
 27→    private lateinit var viewModel: HistoryViewModel
 28→
 29→    @Inject
 30→    lateinit var viewModelFactory: ViewModelProvider.Factory
 31→
 32→    companion object {
 33→        private const val KEY_POST_LOCAL_ID = "key_post_local_id"
 34→        private const val KEY_SITE = "key_site"
 35→
 36→        fun newInstance(postId: Int, site: SiteModel): HistoryListFragment {
 37→            val fragment = HistoryListFragment()
 38→            val bundle = Bundle()
 39→            bundle.putInt(KEY_POST_LOCAL_ID, postId)
 40→            bundle.putSerializable(KEY_SITE, site)
 41→            fragment.arguments = bundle
 42→            return fragment
 43→        }
 44→    }
 45→
 46→    interface HistoryItemClickInterface {
 47→        fun onHistoryItemClicked(revision: Revision, revisions: List<Revision>)
 48→    }
 49→
 50→    private fun onItemClicked(item: HistoryListItem) {
 51→        viewModel.onItemClicked(item)
 52→    }
 53→
 54→    override fun onCreate(savedInstanceState: Bundle?) {
 55→        super.onCreate(savedInstanceState)
 56→
 57→        (requireActivity().application as WordPress).component().inject(this)
 58→
 59→        viewModel = ViewModelProvider(this, viewModelFactory).get(HistoryViewModel::class.java)
 60→    }
 61→
 62→    override fun onAttach(context: Context) {
 63→        super.onAttach(context)
 64→        check(activity is HistoryItemClickInterface) {
 65→            "Parent activity has to implement HistoryItemClickInterface"
 66→        }
 67→    }
 68→
 69→    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
 70→        super.onViewCreated(view, savedInstanceState)
 71→
 72→        val nonNullActivity = requireActivity()
 73→        with(HistoryListFragmentBinding.bind(view)) {
 74→            emptyRecyclerView.layoutManager = LinearLayoutManager(nonNullActivity, RecyclerView.VERTICAL, false)
 75→            emptyRecyclerView.setEmptyView(actionableEmptyView)
 76→            actionableEmptyView.button.setText(R.string.button_retry)
 77→            actionableEmptyView.button.setOnClickListener {
 78→                viewModel.onPullToRefresh()
 79→            }
 80→
 81→            swipeToRefreshHelper = WPSwipeToRefreshHelper.buildSwipeToRefreshHelper(swipeRefreshLayout) {
 82→                viewModel.onPullToRefresh()
 83→            }
 84→
 85→            (nonNullActivity.application as WordPress).component().inject(this@HistoryListFragment)
 86→
 87→            viewModel = ViewModelProvider(this@HistoryListFragment, viewModelFactory)[HistoryViewModel::class.java]
 88→            val site = requireNotNull(arguments?.getSerializableCompat<SiteModel>(KEY_SITE))
 89→            viewModel.create(
 90→                localPostId = arguments?.getInt(KEY_POST_LOCAL_ID) ?: 0,
 91→                site = site
 92→            )
 93→            updatePostOrPageEmptyView()
 94→            setObservers()
 95→        }
 96→    }
 97→
 98→    private fun HistoryListFragmentBinding.updatePostOrPageEmptyView() {
 99→        actionableEmptyView.title.text = getString(R.string.history_empty_title)
100→        actionableEmptyView.button.visibility = View.GONE
101→        actionableEmptyView.subtitle.visibility = View.VISIBLE
102→    }
103→
104→    private fun HistoryListFragmentBinding.reloadList(data: List<HistoryListItem>) {
105→        setList(data)
106→    }
107→
108→    private fun HistoryListFragmentBinding.setList(list: List<HistoryListItem>) {
109→        val adapter: HistoryAdapter
110→
111→        if (emptyRecyclerView.adapter == null) {
112→            adapter = HistoryAdapter(requireActivity(), this@HistoryListFragment::onItemClicked)
113→            emptyRecyclerView.adapter = adapter
114→        } else {
115→            adapter = emptyRecyclerView.adapter as HistoryAdapter
116→        }
117→
118→        adapter.updateList(list)
119→    }
120→
121→    private fun HistoryListFragmentBinding.setObservers() {
122→        viewModel.revisions.observe(viewLifecycleOwner, Observer {
123→            reloadList(it ?: emptyList())
124→        })
125→
126→        viewModel.listStatus.observe(viewLifecycleOwner, Observer { listStatus ->
127→            listStatus?.let {
128→                if (isAdded && view != null) {
129→                    swipeToRefreshHelper.isRefreshing = listStatus == HistoryListStatus.FETCHING
130→                }
131→                when (listStatus) {
132→                    HistoryListStatus.DONE -> {
133→                        updatePostOrPageEmptyView()
134→                    }
135→                    HistoryListStatus.FETCHING -> {
136→                        actionableEmptyView.title.setText(R.string.history_fetching_revisions)
137→                        actionableEmptyView.subtitle.visibility = View.GONE
138→                        actionableEmptyView.button.visibility = View.GONE
139→                    }
140→                    HistoryListStatus.NO_NETWORK -> {
141→                        actionableEmptyView.title.setText(R.string.no_network_title)
142→                        actionableEmptyView.subtitle.setText(R.string.no_network_message)
143→                        actionableEmptyView.subtitle.visibility = View.VISIBLE
144→                        actionableEmptyView.button.visibility = View.VISIBLE
145→                    }
146→                    HistoryListStatus.ERROR -> {
147→                        actionableEmptyView.title.setText(R.string.no_network_title)
148→                        actionableEmptyView.subtitle.setText(R.string.error_generic_network)
149→                        actionableEmptyView.subtitle.visibility = View.VISIBLE
150→                        actionableEmptyView.button.visibility = View.VISIBLE
151→                    }
152→                }
153→            }
154→        })
155→
156→        viewModel.showDialog.observe(viewLifecycleOwner, Observer { showDialogItem ->
157→            if (showDialogItem != null && showDialogItem.historyListItem is Revision) {
158→                (activity as HistoryItemClickInterface).onHistoryItemClicked(
159→                    showDialogItem.historyListItem,
160→                    showDialogItem.revisionsList
161→                )
162→            }
163→        })
164→
165→        viewModel.post.observe(viewLifecycleOwner, Observer { post ->
166→            actionableEmptyView.subtitle.text = if (post?.isPage == true) {
167→                getString(R.string.history_empty_subtitle_page)
168→            } else {
169→                getString(R.string.history_empty_subtitle_post)
170→            }
171→        })
172→    }
173→}
